import{_ as e,a as t,b as i}from"./chunks/支持留言.NiGCLVdp.js";import{_ as s,o as l,c as o,a2 as p}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Блог","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/Other/blog.md","filePath":"uk-UA/Other/blog.md","lastUpdated":1781962217000}'),n={name:"uk-UA/Other/blog.md"};function d(c,a,r,h,g,b){return l(),o("div",null,[...a[0]||(a[0]=[p('<h1 id="блог" tabindex="-1">Блог <a class="header-anchor" href="#блог" aria-label="Permalink to &quot;Блог&quot;">​</a></h1><p>Функція блогу додає до сайту ImgBed окрему сторінку блогу.</p><p>Після ввімкнення відвідувачі можуть відкрити:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+e+'" alt="Головна сторінка блогу" loading="lazy"></p><p>Блог адаптований з open-source проєкту <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a>. ImgBed переписує та інтегрує його з Vue, щоб він працював як частина сайту зображень.</p><h2 id="де-це-налаштовується" tabindex="-1">Де це налаштовується <a class="header-anchor" href="#де-це-налаштовується" aria-label="Permalink to &quot;Де це налаштовується&quot;">​</a></h2><p>Налаштування блогу знаходяться тут:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+t+'" alt="Налаштування блогу" loading="lazy"></p><h2 id="перше-налаштування" tabindex="-1">Перше налаштування <a class="header-anchor" href="#перше-налаштування" aria-label="Permalink to &quot;Перше налаштування&quot;">​</a></h2><ol><li>Увімкніть <code>Enable</code>.</li><li>Виберіть GitHub-акаунт, у якому зберігатиметься конфігурація блогу.</li><li>Натисніть <code>Update Blog</code>.</li><li>Дочекайтеся повідомлення про успіх.</li><li>Відкрийте <code>https://your-domain.com/blog/</code>, щоб переглянути блог.</li></ol><p>Під час першого використання ImgBed підготує приватний GitHub-репозиторій у вибраному акаунті:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>У цьому репозиторії зберігаються налаштування блогу й тексти статей.</p><h2 id="написання-дописів" tabindex="-1">Написання дописів <a class="header-anchor" href="#написання-дописів" aria-label="Permalink to &quot;Написання дописів&quot;">​</a></h2><p>Редагуйте дописи блогу у своєму приватному GitHub-репозиторії:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Типовий процес:</p><ol><li>Відкрийте GitHub.</li><li>Перейдіть у приватний репозиторій <code>imgbed-blog-config</code>.</li><li>Відредагуйте або додайте файли дописів.</li><li>Закомітьте зміни.</li><li>Поверніться до адмін-панелі ImgBed і натисніть <code>Update Blog</code>, або тричі натисніть логотип у лівому верхньому куті головної сторінки блогу, щоб запустити оновлення.</li></ol><p><code>Update Blog</code> не перезаписує написаний вами контент. Він ініціалізує репозиторій, коли це потрібно, і оновлює кеш блогу.</p><h2 id="підтримувані-можливості" tabindex="-1">Підтримувані можливості <a class="header-anchor" href="#підтримувані-можливості" aria-label="Permalink to &quot;Підтримувані можливості&quot;">​</a></h2><p>Блог підтримує типові функції: список дописів, категорії, теги, архів, пошук, темний режим і перемикання мови.</p><p>Також підтримуються коментарі й статистика відвідувань.</p><p><img src="'+i+'" alt="Коментарі блогу" loading="lazy"></p><p>Коментарі показуються під дописами. Відвідувачі можуть вказати avatar, nickname, email і текст коментаря.</p><p>Статистика відвідувань показує перегляди дописів і відвідини сайту, щоб ви краще розуміли трафік блогу.</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>Блог завжди доступний за шляхом <code>/blog/</code>.</p><p>Наприклад, якщо домен ImgBed:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>URL блогу буде:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>Після вимкнення блогу відвідувачі більше не зможуть відкрити сторінку блогу.</p>',34)])])}const v=s(n,[["render",d]]);export{k as __pageData,v as default};
